class Solution {
public:
    int maxTaskAssign(vector<int>& tasks, vector<int>& workers, int pills, int strength) {
        sort(tasks.begin(), tasks.end());
        sort(workers.begin(), workers.end());
        int i = tasks.size() - 1, j = workers.size() - 1, res = 0;
        while (i >= 0 && j >= 0) {
            if (workers[j] + pills * strength >= tasks[i]) {
                res++;
                i--;
                j--;
                pills--;
            } else {
                j--;
            }
        }
        j = workers.size() - 1;
        while (i >= 0 && j >= 0 && pills > 0) {
            if (workers[j] + strength >= tasks[i]) {
                res++;
                i--;
                j--;
                pills--;
            } else {
                j--;
            }
        }
        return res;
    }
};
```
